import React, { useContext, useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { AuthContext } from '../App';
import { API_URL } from '../config';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';

const Dashboard = () => {
  const { token, user, logout } = useContext(AuthContext);
  const [workouts, setWorkouts] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    let isMounted = true;

    const fetchWorkouts = async () => {
      if (token) {
        try {
          const res = await fetch(`${API_URL}/api/workouts`, {
            headers: { 'x-auth-token': token },
          });
          if (!isMounted) return;

          if (res.ok) {
            const data = await res.json();
            setWorkouts(data);
          } else if (res.status === 401) {
             // Handle 401 locally if needed, but App.js already handles global logout
             console.log('Workouts fetch returned 401');
          }
        } catch (err) {
          console.error('Failed to fetch workouts:', err);
        }
      }
    };

    fetchWorkouts();

    return () => {
      isMounted = false;
    };
  }, [token]);

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this workout?')) return;
    try {
      const res = await fetch(`${API_URL}/api/workouts/${id}`, {
        method: 'DELETE',
        headers: { 'x-auth-token': token },
      });
      if (res.ok) {
        setWorkouts(workouts.filter((w) => w._id !== id));
      }
    } catch (err) {
      console.error(err);
    }
  };

  // Prepare data for chart (example: total weight lifted per session)
  // Only include days with actual weightlifting volume
  const chartData = Object.keys(groupedWorkouts).reverse().map(dateKey => {
    return {
      date: dateKey.split(' ')[0], // just take "3月15日" part
      totalWeight: groupedWorkouts[dateKey].totalVol,
    };
  }).filter(data => data.totalWeight > 0);

  const totalWorkouts = workouts.length;
  const totalVolume = workouts.reduce((acc, w) => acc + getWorkoutVolume(w), 0);
  const activeDays = new Set(workouts.map(w => new Date(w.date).toLocaleDateString())).size;

  // Helper function to calculate volume for a specific workout
  const getWorkoutVolume = (w) => {
    if (isCardio(w.exercise)) return 0; // Don't add cardio duration/cals to weight volume
    return w.sets.reduce((acc, s) => acc + (s.weight * s.reps), 0);
  };

  // V3.0 Group workouts by date to create the "Session" view
  const groupedWorkouts = workouts.reduce((acc, w) => {
    const rawDate = new Date(w.date);
    const dateStr = rawDate.toLocaleDateString('zh-CN', { month: 'long', day: 'numeric', weekday: 'long' });
    if (!acc[dateStr]) acc[dateStr] = { rawDate, items: [], totalVol: 0 };
    acc[dateStr].items.push(w);
    acc[dateStr].totalVol += getWorkoutVolume(w);
    return acc;
  }, {});

  const sortedDates = Object.keys(groupedWorkouts).sort((a, b) => {
    return groupedWorkouts[b].rawDate - groupedWorkouts[a].rawDate;
  });

  const isCardio = (ex) => {
    return ex.includes('跑') || ex.includes('骑') || ex.includes('椭圆机') || ex.includes('划船机') || ex.includes('跳绳') || ex.includes('有氧');
  };

  return (
    <div>
      <nav className="nav">
        <h1>{user ? `${user.username} 的健身记录` : '健身记录'}</h1>
        <div style={{display: 'flex', alignItems: 'center'}}>
          {user && <span className="nav-greeting" style={{marginRight: '20px', fontWeight: 500}}>你好，{user.username}</span>}
          <Link to="/add"><button style={{marginRight: '10px'}}>+ 添加训练</button></Link>
          <button className="secondary" onClick={logout}>退出登录</button>
        </div>
      </nav>

      <div className="hero-section">
        <h1 style={{marginTop: '40px', marginBottom: '10px'}}>{user ? `欢迎回来，${user.username}。` : '今天准备好大干一场了吗？'}</h1>
        <p style={{color: 'var(--apple-text-secondary)', fontSize: '18px', marginBottom: '40px'}}>这是你目前的训练进度总结。</p>
      </div>

      <div className="stats-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px', marginBottom: '40px' }}>
        <div className="stat-card">
          <h3>训练次数</h3>
          <p className="stat-value">{totalWorkouts}</p>
        </div>
        <div className="stat-card">
          <h3>总容量 (kg)</h3>
          <p className="stat-value">{totalVolume.toLocaleString()}</p>
        </div>
        <div className="stat-card" style={{background: 'rgba(255, 149, 0, 0.1)', border: '1px solid rgba(255,149,0,0.2)'}}>
          <h3 style={{color: '#d87000'}}>有氧消耗 (大卡)</h3>
          <p className="stat-value" style={{color: '#ff9500'}}>
            {workouts.filter(w => isCardio(w.exercise)).reduce((acc, w) => acc + (w.sets[0]?.reps || 0), 0)}
          </p>
        </div>
      </div>

      {workouts.length > 0 && (
        <div className="chart-container" style={{ height: 400, marginBottom: 40 }}>
          <h3>容量趋势</h3>
          <ResponsiveContainer width="100%" height="80%">
            <LineChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(0,0,0,0.05)" />
              <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fill: 'var(--apple-text-secondary)'}} dy={10} />
              <YAxis axisLine={false} tickLine={false} tick={{fill: 'var(--apple-text-secondary)'}} dx={-10} />
              <Tooltip 
                contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: 'var(--apple-shadow)' }}
                cursor={{ stroke: 'rgba(0,113,227,0.1)', strokeWidth: 2 }}
              />
              <Line type="monotone" dataKey="totalWeight" stroke="var(--apple-blue)" strokeWidth={3} dot={{r: 4, fill: 'var(--apple-blue)'}} activeDot={{r: 6}} />
            </LineChart>
          </ResponsiveContainer>
        </div>
      )}

      <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px'}}>
        <h2 style={{margin: 0}}>最近活动</h2>
      </div>

      {workouts.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">🏋️</div>
          <h3>你的训练之旅从这里开始</h3>
          <p>你还没有记录任何训练。记录下你的第一次训练，开始追踪进度吧！</p>
          <Link to="/add"><button style={{marginTop: '20px'}}>开始第一次训练</button></Link>
        </div>
      ) : (
        <div className="daily-groupings">
          {sortedDates.map(dateKey => {
            const dayData = groupedWorkouts[dateKey];
            return (
              <div key={dateKey} className="daily-group">
                <div className="daily-header">
                  <h3>{dateKey}</h3>
                  <div style={{display: 'flex', gap: '15px'}}>
                    {dayData.totalVol > 0 && <span className="daily-meta">容量 {dayData.totalVol.toLocaleString()} kg</span>}
                    {dayData.items.some(w => isCardio(w.exercise)) && (
                      <span className="daily-meta" style={{color: '#ff9500'}}>
                        🔥 {dayData.items.filter(w => isCardio(w.exercise)).reduce((acc, w) => acc + w.sets[0].reps, 0)} 千卡
                      </span>
                    )}
                  </div>
                </div>

                {dayData.items.map(w => (
                  <div key={w._id} className="exercise-card">
                    <div className="exercise-header">
                      <h4>{w.exercise}</h4>
                      <button className="delete-btn" onClick={() => handleDelete(w._id)}>删除</button>
                    </div>

                    <div className="set-list">
                      {w.sets.map((s, i) => (
                        <div key={i} className="set-item">
                          {!isCardio(w.exercise) && <span className="set-item-index">#{i + 1}</span>}
                          {isCardio(w.exercise) ? (
                            <>
                              <span>{s.weight} 分钟</span>
                              <span style={{color: 'var(--apple-blue)'}}>{s.reps} 大卡</span>
                            </>
                          ) : (
                            <>
                              <span>{s.weight === 0 ? '自重' : `${s.weight} kg`}</span>
                              <span>{s.reps} 次</span>
                            </>
                          )}
                        </div>
                      ))}
                    </div>
                    {w.notes && <div style={{marginTop: '12px', fontSize: '14px', color: 'var(--apple-text-secondary)', background: 'var(--apple-bg)', padding: '10px', borderRadius: '8px'}}>{w.notes}</div>}
                  </div>
                ))}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default Dashboard;
